// Minimal bar chart implementation for GreenPrompt dashboard
(function(global) {
  class Chart {
    constructor(ctx, config) {
      this.ctx = ctx;
      this.config = config;
      this.canvas = ctx.canvas;
      this._draw();
    }
    _draw() {
      const { type, data, options } = this.config;
      if (type === 'bar') this._drawBar(data, options);
      else if (type === 'doughnut') this._drawDoughnut(data, options);
    }
    _drawBar(data, opts) {
      const canvas = this.canvas;
      const ctx = this.ctx;
      const W = canvas.width  = canvas.offsetWidth  || 400;
      const H = canvas.height = canvas.offsetHeight || 180;
      ctx.clearRect(0, 0, W, H);

      const labels = data.labels || [];
      const dataset = data.datasets[0];
      const values = dataset.data || [];
      if (!values.length) return;

      const padL = 30, padR = 10, padT = 10, padB = 30;
      const chartW = W - padL - padR;
      const chartH = H - padT - padB;
      const maxVal = Math.max(...values, 0.001);
      const barW = (chartW / values.length) * 0.6;
      const gap  = (chartW / values.length) * 0.4;

      // Grid lines
      ctx.strokeStyle = 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 1;
      for (let i = 0; i <= 4; i++) {
        const y = padT + chartH - (i / 4) * chartH;
        ctx.beginPath(); ctx.moveTo(padL, y); ctx.lineTo(W - padR, y); ctx.stroke();
        ctx.fillStyle = '#52685a';
        ctx.font = '9px Courier New';
        ctx.textAlign = 'right';
        ctx.fillText((maxVal * i / 4).toFixed(2), padL - 3, y + 3);
      }

      // Bars
      values.forEach((v, i) => {
        const x = padL + i * (chartW / values.length) + gap / 2;
        const barH = (v / maxVal) * chartH;
        const y = padT + chartH - barH;
        const colors = Array.isArray(dataset.backgroundColor)
          ? dataset.backgroundColor[i] : (dataset.backgroundColor || 'rgba(74,222,128,0.7)');
        ctx.fillStyle = colors;
        const r = Math.min(3, barW / 2);
        ctx.beginPath();
        ctx.roundRect ? ctx.roundRect(x, y, barW, barH, [r, r, 0, 0])
          : ctx.rect(x, y, barW, barH);
        ctx.fill();

        // Label
        ctx.fillStyle = '#52685a';
        ctx.font = '9px Courier New';
        ctx.textAlign = 'center';
        ctx.fillText(labels[i] || '', x + barW / 2, H - padB + 12);
      });
    }
    _drawDoughnut(data, opts) {
      const canvas = this.canvas;
      const ctx = this.ctx;
      const W = canvas.width  = canvas.offsetWidth  || 200;
      const H = canvas.height = canvas.offsetHeight || 200;
      ctx.clearRect(0, 0, W, H);
      const cx = W/2, cy = H/2, r = Math.min(W,H)*0.38, inner = r*0.6;
      const vals = data.datasets[0].data;
      const total = vals.reduce((a,b)=>a+b,0)||1;
      const colors = data.datasets[0].backgroundColor || ['#4ade80','#34d399','#86efac'];
      let start = -Math.PI/2;
      vals.forEach((v,i) => {
        const slice = (v/total)*Math.PI*2;
        ctx.beginPath();
        ctx.moveTo(cx,cy);
        ctx.arc(cx,cy,r,start,start+slice);
        ctx.closePath();
        ctx.fillStyle = colors[i % colors.length];
        ctx.fill();
        start += slice;
      });
      ctx.beginPath();
      ctx.arc(cx,cy,inner,0,Math.PI*2);
      ctx.fillStyle = '#0a1510';
      ctx.fill();
    }
    destroy() {}
    update() { this._draw(); }
  }
  global.Chart = Chart;
})(window);
